#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int maxProfit(vector<int>& prices) {
        if (prices.empty()) {
            return 0;
        }

        int n = prices.size();
        int buy = -prices[0];
        int sell = 0;
        int cooldown = 0;

        for (int i = 1; i < n; i++) {
            int new_buy = max(buy, cooldown - prices[i]);
            int new_sell = max(sell, buy + prices[i]);
            int new_cooldown = max(cooldown, sell);

            buy = new_buy;
            sell = new_sell;
            cooldown = new_cooldown;
        }

        return max(sell, cooldown);
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> prices(n);
    for (int i = 0; i < n; i++) cin >> prices[i];
    Solution sol;
    int ans = sol.maxProfit(prices);
    cout << ans << "\n";
    return 0;
}
